SELECT grouping([#mp_probe].event_month) * :grouping_1 + grouping([#mp_probe].lag_day) * :grouping_2 + grouping([#mp_probe].load_epoch_day) * :grouping_3 + :param_1 + :param_2 AS grouping_id, [#mp_probe].event_month AS event_month, [#mp_probe].lag_day AS lag_day, [#mp_probe].load_epoch_day AS load_epoch_day, max([#mp_probe].batch_id) AS batch_id, max([#mp_probe].alt_value) AS alt_value, count(*) AS row_count, sum([#mp_probe].is_eligible) AS n_curve_eligible, sum([#mp_probe].is_null_event_time) AS n_null_event_time, sum([#mp_probe].is_null_load_time_only) AS n_null_load_time_only, sum([#mp_probe].is_negative_clipped) AS n_negative_clipped, sum([#mp_probe].is_negative_lag_excluded) AS n_negative_lag_excluded, sum([#mp_probe].is_overflow) AS n_overflow, sum([#mp_probe].is_join_unmatched) AS n_join_unmatched, max([#mp_probe].lookup_dup) AS max_lookup_dup, CAST(NULL AS BIGINT) AS distinct_keys, min([#mp_probe].load_time) AS min_load_time 
FROM [#mp_probe] GROUP BY GROUPING SETS (([#mp_probe].event_month, [#mp_probe].lag_day), ([#mp_probe].load_epoch_day), ())
